using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train model at startup and register as singleton for label access
var trainingService = new ModelTrainingService(
    LoggerFactory.Create(b => b.AddConsole()).CreateLogger<ModelTrainingService>());
trainingService.TrainAndSaveModel();

builder.Services.AddSingleton(trainingService);
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(trainingService.GetModelPath());

var app = builder.Build();
app.MapControllers();
app.Run();

